/* 字体引入，可注释或更改 */
@import url('https://static.zeoseven.com/zsft/288/main/result.css');

body,
code:not([class*='hljs']) {
  font-family: 'Source Han Sans SC VF';
}

@supports (-webkit-touch-callout: none) {
  /* iOS 使用默认字体 */
  body,
  code:not([class*='hljs']) {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  }
}

/* 主题色配置 */
:root {
  --theme-color-1: var(--SmartThemeQuoteColor);
  /* 对应引用文本 */
  --theme-color-2: var(--SmartThemeUnderlineColor);
  /* 对应下划线 */
  --ui-color-main: var(--SmartThemeBlurTintColor);
  /* 对应UI背景 */
  --ui-color-sec: color-mix(in srgb, var(--ui-color-main) 88%, var(--text-color-main));
  /* 自适应UI次级颜色 */
  --top-bar-color: var(--SmartThemeBorderColor);
  /* 顶栏图标颜色 */
  --chat-background-color: var(--SmartThemeChatTintColor);
  /* 对应聊天背景 */
  --text-color-main: var(--SmartThemeBodyColor);
  /* 对应主要文本 */
  --text-color-sec: var(--SmartThemeEmColor);
  /* 对应斜体文本 */
  --user-color: var(--SmartThemeUserMesBlurTintColor);
  /* 对应用户消息模糊色调 */
  --char-color: var(--SmartThemeBotMesBlurTintColor);
  /* 对应AI消息模糊色调 */
  --code-color: var(--SmartThemeShadowColor);
  /* 对应阴影颜色 */
  --gradient-main: linear-gradient(
    135deg,
    var(--theme-color-1) 30%,
    color-mix(in srgb, var(--theme-color-1) 50%, var(--theme-color-2) 50%) 50%,
    var(--theme-color-2) 70%
  );
  /* 主题渐变 */
  --blur-amount: 10px;
  /* 高斯模糊数值 */
  --blur-opacity: 0.8;
  /* 模糊后背景透明度 */
  --blur-bg-light: rgba(255, 255, 255, 0.3);
  /* 模糊背景浅色 */
  --blur-bg-top: color-mix(in srgb, var(--top-bar-color) 70%, transparent);
  /* 模糊聊天背景 */
  --blur-bg-chat: color-mix(in srgb, var(--chat-background-color) 70%, transparent);
  /* 模糊输入框背景 - 增加了不透明度 */
  --input-text-shadow: 0 0 0 rgba(0, 0, 0, 0); /* 输入文本阴影，默认无 */
  --panel-shadow: 0 0 20px rgba(0, 0, 0, 0.25), 0 0 6px rgba(0, 0, 0, 0.15); /* 侧边栏阴影 */
  --mes-width: 100%;
  /* 此百分比调整聊天气泡与整体聊天界面的距离 */
  --mes-block-width: 98%;
  /* 此百分比调整聊天记录文字与气泡左右边框的距离 */
  --box-border-radius: 5px;
  /* 所有盒子的圆角大小 */
  --top-distance: 5px;
  /* 顶栏与上边沿的距离 */
  --bottom-distance: 0px;
  /* 底栏与下边沿的距离 */
  --chat-send-spacing: 0px;
  /* 聊天界面与发送框的距离，改为0实现无缝连接 */
  --leftRight-chat-spacing: 10px;
  /* 聊天界面与左右边沿的距离，电脑端专供 */
  --scroll-width: 5px;
  /* 滚动条宽度 */
  --icon-size: var(--mainFontSize);
  /* 图标大小 */
  --border-radius-small: 5px;
  --border-radius-medium: 10px;
  --spacing-long: 10px;
  --spacing-short: 5px;
  --topBarIconSize: calc(var(--icon-size) * 2);
}

:root {
  --mes-width: 100%;
  /* 此百分比调整聊天气泡与整体聊天界面的距离 */
  --mes-block-width: 98%;
  /* 此百分比调整聊天记录文字与气泡左右边框的距离 */
  --box-border-radius: 5px;
  /* 所有盒子的圆角大小 */
  --top-distance: 5px;
  /* 顶栏与上边沿的距离 */
  --bottom-distance: 0px;
  /* 底栏与下边沿的距离 */
  --chat-send-spacing: 0px;
  /* 聊天界面与发送框的距离，改为0实现无缝连接 */
  --leftRight-chat-spacing: 10px;
  /* 聊天界面与左右边沿的距离，电脑端专供 */
  --scroll-width: 5px;
  /* 滚动条宽度 */
  --icon-size: var(--mainFontSize);
  /* 图标大小 */
  --border-radius-small: 5px;
  --border-radius-medium: 10px;
  --spacing-long: 10px;
  --spacing-short: 5px;
  --topBarIconSize: calc(var(--icon-size) * 2);
}

/* ---标题--- */

/* 标题装饰 */
.standoutHeader strong,
#right-nav-panel h2,
.drawer-content > h3,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter),
.drawer-content .flex-container .flex-container h3:first-of-type,
.popup h3:not(dialog *) {
  font-size: calc(var(--mainFontSize) * 1.2);
  color: var(--text-color-main);
  letter-spacing: 0.1em;
  white-space: nowrap;
  line-height: 2;
}

.standoutHeader strong::before,
#right-nav-panel h2::before,
.drawer-content > h3::before,
.drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter)::before,
.drawer-content .flex-container .flex-container h3:first-of-type::before,
.popup h3:not(dialog *)::before {
  content: '✦';
  position: relative;
  background: var(--gradient-main);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  font-size: calc(var(--mainFontSize) * 1.3);
  text-shadow: none;
  padding-bottom: 0.5px;
}

@supports (-webkit-touch-callout: none) {
  .standoutHeader strong::before,
  #right-nav-panel h2::before,
  .drawer-content > h3::before,
  .drawer-content .flex-container h3:first-of-type:not(#Backgrounds .textAlignCenter)::before,
  .drawer-content .flex-container .flex-container h3:first-of-type::before,
  .popup h3:not(dialog *)::before {
    font-size: calc(var(--mainFontSize) * 1.7);
  }
}

/* 增加标题下横线 */
.standoutHeader:not(h4),
#rm_PinAndTabs,
#top-settings-holder .drawer:not(:first-child):not(:last-child) .drawer-content .alignItemsBaseline.wide100p,
#rm_api_block .flex-container.alignItemsBaseline,
#title_api,
#AdvancedFormatting .flex-container.alignItemsBaseline:not(h3),
#WorldInfo .alignitemscenter:not(#world_popup *),
#user-settings-block div[name='userSettingsRowOne'],
#rm_extensions_block .alignitemscenter.flex-container.wide100p:not(.justifyCenter) {
  background-image: none;
  border-radius: 0;
  border: none;
  border-bottom: 1px solid var(--ui-color-sec);
  margin-bottom: calc(var(--mainFontSize) * 0.4);
  padding-bottom: calc(var(--mainFontSize) * 0.2);
}

/* 修正标题没对齐的问题 */
.drawer-content .alignItemsBaseline {
  align-items: center !important;
}

#title_api {
  padding-bottom: 0;
}

#title_api::before,
#Backgrounds h3.margin0.flex2::before,
#rm_extensions_block .margin0.flex1::before,
#rm_button_selected_ch h2::before {
  margin-right: calc(var(--mainFontSize) * 0.4);
}

/* ---抽屉--- */
/* 覆盖样式 */
.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#top-settings-holder h4:not(#ai-config-button *):not(#rightNavHolder *) {
  border-width: 0 0 0 3px !important;
  border-color: transparent !important;
  border-style: solid;
  border-radius: 0;
  background-image: none !important;
  padding-left: 7px;
  border-image: linear-gradient(
      to bottom,
      transparent 25%,
      var(--theme-color-1) 25%,
      var(--theme-color-1) 75%,
      transparent 75%
    )
    1 100%;
}

/* 缩小箭头图标 */
.inline-drawer-icon {
  font-size: var(--icon-size);
}

/* ---滚动条--- */
::-webkit-scrollbar {
  width: var(--scroll-width);
}

::-webkit-scrollbar:horizontal {
  height: var(--scroll-width);
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
  background-color: color-mix(in srgb, var(--theme-color-1) 70%, transparent);
  box-shadow: none;
  border: 0;
}

/* ---输入框--- */
input[type='text'],
input[type='number'],
input[type='switch'],
input:not([type]),
textarea:not([type='search']) {
  background-color: var(--ui-color-sec) !important;
  border: 1px solid var(--ui-color-sec) !important;
}

input[type='text']:focus,
input[type='number']:focus,
input[type='switch']:focus,
input:not([type]):focus,
textarea:not([type='search']):focus {
  border: 1px solid var(--theme-color-1) !important;
}

textarea[type='search'] {
  background-color: transparent !important;
  border: none !important;
}

.range-block {
  margin: calc(var(--mainFontSize) * 0.6) 0;
}

.range-block-counter {
  margin-left: 20px;
}

.text_pole:not(.objective-task) {
  background-color: var(--ui-color-sec);
  border: none;
}

/* ---按键--- */
.menu_button:not(.mes_edit_buttons *) {
  background-color: var(--ui-color-sec);
  border-color: var(--ui-color-sec);
  color: var(--text-color-main);
}

.menu_button_icon i {
  font-size: calc(var(--icon-size) * 0.8);
}

#delete_button,
#dialogue_del_mes_ok,
#dialogue_popup_ok,
#bulk_tag_popup_reset,
#bulk_tag_popup_remove_mutual,
.mes_edit_cancel.menu_button,
.menu_button.popup-button-ok,
.redWarningBG {
  background-color: var(--crimson70a) !important;
  color: var(--white100) !important;
}

/* 去除阴影 */
.mes_button,
.mes_edit_buttons,
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span {
  filter: none !important;
}

.fa-solid:not(#load-spinner) {
  font-size: var(--icon-size);
  text-shadow: none !important;
}

/* ---下拉框--- */
select {
  background-color: var(--ui-color-sec) !important;
  color: var(--text-color-main);
  border: none !important;
  margin: calc(var(--mainFontSize) * 0.3) 0 !important;
}

select option:not(:checked) {
  color: var(--text-color-sec);
}

select option:checked {
  color: var(--ui-color-sec);
  background-color: var(--text-color-main) !important;
}

select option {
  background-color: var(--ui-color-sec) !important;
}

.ui-widget-content .ui-state-active {
  color: var(--theme-color-1) !important;
}

/* ---勾选框--- */
input[type='checkbox'] {
  width: calc(var(--mainFontSize) * 0.9);
  height: calc(var(--mainFontSize) * 0.9);
  border: none;
  outline: none;
  background-color: var(--ui-color-main);
  filter: none;
  box-shadow: 0 0 0 1px var(--text-color-sec);
  transform: translateY(0);
  margin-left: 1px;
}

input[type='checkbox']::before {
  box-shadow: inset 1em 1em var(--theme-color-1);
}

input[type='checkbox'].del_checkbox {
  margin-right: 0;
}

/* ---滑动条--- */
input[type='range'] {
  box-shadow: none;
  background-color: var(--ui-color-sec) !important;
}

input[type='range']:hover {
  background-color: color-mix(in srgb, var(--ui-color-sec) 70%, black 30%) !important;
}

input[type='range']::-webkit-slider-thumb {
  box-shadow: 0 0 0 3px color-mix(in srgb, var(--theme-color-1) 50%, transparent);
  background-color: var(--theme-color-1);
  width: 10px;
  height: 10px;
}

.neo-range-slider {
  box-shadow: inset 0 0 0 3px rgba(0, 0, 0, 0.2) !important;
}

/* ---盒子--- */
/* 统一样式 */
#left-nav-panel,
#right-nav-panel,
#character_popup,
#dialogue_popup,
#chat,
.draggable,
#select_chat_popup,
.popup:not(.transparent_dialogue_popup),
.drawer-content {
  padding: var(--spacing-long);
  background-color: var(--ui-color-main);
  border-radius: var(--box-border-radius);
  border: none;
}

#dialogue_popup_text {
  padding: 0 var(--spacing-long) 0 0;
}

#left-nav-panel,
#right-nav-panel {
  top: var(--top-distance);
  height: 100dvh !important;
  max-height: calc(100dvh - var(--top-distance) - var(--bottom-distance) - 1px);
  box-shadow: var(--panel-shadow); /* 添加侧边栏阴影 */
  border: 1px solid color-mix(in srgb, var(--theme-color-1) 20%, transparent); /* 添加细边框增强边界感 */
  z-index: 10; /* 确保层级高于其他元素 */
  transition: box-shadow 0.3s ease, border-color 0.3s ease; /* 添加过渡效果 */
}

/* 当鼠标悬停在侧边栏上时提供额外的视觉反馈 */
#left-nav-panel:hover,
#right-nav-panel:hover {
  border-color: color-mix(in srgb, var(--theme-color-1) 40%, transparent); /* 边框颜色加深 */
}

/* 当左侧面板展开时，提供视觉反馈 */
body.PanelActive[lp='1'] #left-nav-panel {
  box-shadow: 8px 0 25px rgba(0, 0, 0, 0.3), 0 0 10px rgba(0, 0, 0, 0.2); /* 右侧阴影更强 */
}

/* 当右侧面板展开时，提供视觉反馈 */
body.PanelActive[rp='1'] #right-nav-panel {
  box-shadow: -8px 0 25px rgba(0, 0, 0, 0.3), 0 0 10px rgba(0, 0, 0, 0.2); /* 左侧阴影更强 */
}

@media screen and (max-width: 1000px) {
  #left-nav-panel,
  #right-nav-panel,
  .drawer-content {
    margin-top: var(--top-distance);
  }

  #left-nav-panel,
  #right-nav-panel {
    height: calc(100dvh - 45px) !important;
    max-height: calc(100dvh - var(--topBarBlockSize)) !important;
    border-radius: 0 0 var(--border-radius-small) var(--border-radius-small);
  }
}

/* ---列表--- */
.list-group,
.options-content {
  border: none;
  border-radius: var(--border-radius-small);
  background-color: var(--ui-color-sec) !important;
}

#options {
  background-color: transparent !important;
  padding: 0;
}

/* ---图标--- */
.fa-fw:not(#qr--modal-icon) {
  width: auto;
}

/* 缩小锁定图标 */
#rm_button_characters,
#rm_button_panel_pin_div,
#lm_button_panel_pin_div,
#WI_button_panel_pin_div {
  font-size: var(--icon-size);
}

/* ---头像--- */
.avatar img,
body.big-avatars .avatar img {
  box-shadow: none;
  border: none;
}
.mesAvatarWrapper .avatar img {
  image-rendering: crisp-edges;
  width: 51px;
  height: 77px;
  object-fit: cover;
}

/* ---代码块--- */
code {
  margin: 0;
  border: none;
  background-color: var(--code-color);
}

body[data-stscript-style] .hljs.language-stscript,
.hljs {
  background: var(--code-color);
}

.custom-mermaid {
  background-color: var(--code-color);
}

/* 浅色代码块样式 */

#chat pre code,
#chat .custom-code,
#chat .hljs {
  font-family: 'Source Code Pro', 'JetBrains Mono', 'Consolas', monospace;
  padding: 12px 16px;
  margin: 8px 0;
  border-radius: var(--border-radius-medium);
  border-left: 3px solid var(--theme-color-1);

  line-height: 1.5;
  font-size: 0.92em;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-word;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.08);
  transition: all 0.3s ease;
}

/* 代码块悬停效果 */
#chat code:hover,
#chat pre code:hover,
#chat .custom-code:hover,
#chat .hljs:hover {
  border-left: 3px solid var(--theme-color-2);
  box-shadow: 0 3px 8px rgba(0, 0, 0, 0.12);

}

/* 行内代码样式 */
#chat code,
#chat p code,
#chat li code,
#chat span:not(.hljs) > code {
  padding: 2px 6px;
  margin: 0 2px;
  border-radius: var(--border-radius-small);
  border-left: 2px solid var(--theme-color-1);
  font-size: 0.9em;
  white-space: pre-wrap;
  word-break: break-word;
  vertical-align: middle;
}

/* 代码块内的滚动条样式 */
#chat code::-webkit-scrollbar,
#chat .hljs::-webkit-scrollbar {
  height: 6px;
  background-color: rgba(240, 240, 240, 0.5);
}

#chat code::-webkit-scrollbar-thumb,
#chat .hljs::-webkit-scrollbar-thumb {
  background-color: color-mix(in srgb, var(--theme-color-1) 60%, white);
  border-radius: 3px;
}

#chat code::-webkit-scrollbar-thumb:hover,
#chat .hljs::-webkit-scrollbar-thumb:hover {
  background-color: var(--theme-color-1);
}


.hljs-emphasis {
  font-style: italic;
}

.hljs-strong {
  font-weight: bold;
}

*/
/* 代码块行号样式 (如果支持) */
.hljs-ln-numbers {
  user-select: none;
  text-align: center;
  color: var(--text-color-sec);
  border-right: 1px solid var(--ui-color-sec);
  vertical-align: top;
  padding-right: 8px !important;
  padding-left: 4px !important;
}

.hljs-ln-code {
  padding-left: 10px !important;
}

/* 移动设备上的代码块样式优化 */
@media (max-width: 768px) {
  #chat code,
  #chat pre code,
  #chat .custom-code,
  #chat .hljs {
    padding: 10px 12px;
    font-size: 0.85em;
  }

  /* 确保在移动设备上代码块不会溢出屏幕 */
  #chat code,
  #chat .hljs {
    max-width: calc(100vw - 60px);
    white-space: pre-wrap;
    word-break: break-word;
  }
}

/* 确保代码框架在所有主题模式下都能正常显示 */
body.waifuMode #chat code,
body.waifuMode #chat .hljs,
body.waifuMode #chat .custom-code {
  background-color: color-mix(in srgb, rgba(30, 30, 35, 0.7) 90%, var(--theme-color-1) 10%);
  border-left: 3px solid var(--theme-color-1);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
}

body.documentstyle #chat code,
body.documentstyle #chat .hljs,
body.documentstyle #chat .custom-code {
  border: 1px solid var(--ui-color-sec);
  border-left: 3px solid var(--theme-color-1);
}

/* ---引用块--- */
#chat blockquote {
  border-left: 3px solid var(--theme-color-1);
  padding: 2px 8px;
  background-color: color-mix(in srgb, var(--theme-color-1) 10%, transparent);
  border-radius: var(--border-radius-small);
}

#chat blockquote p {
  color: var(--text-color-main);
  margin: 5px 0;
}

#chat blockquote a {
  color: var(--theme-color-1);
  text-decoration: none;
}

#chat blockquote a:hover {
  text-decoration: underline;
}

body.no-blur #top-bar,
#top-bar {
  border-radius: var(--border-radius-small) var(--border-radius-small) 0 0;
  box-shadow: none;
  background-color: var(--blur-bg-top) !important;
  backdrop-filter: blur(var(--blur-amount));
  -webkit-backdrop-filter: blur(var(--blur-amount));
}

body.waifuMode #top-bar {
  border: none;
}

#top-settings-holder {
  top: var(--top-distance);
  box-shadow: 0 2px 0 0 var(--top-bar-underline-color);

  -webkit-backdrop-filter: blur(var(--blur-amount));
}

#top-settings-holder > :first-child {
  border-radius: var(--box-border-radius) 0 0 0;
}

#top-settings-holder > :last-child {
  border-radius: 0 var(--box-border-radius) 0 0;
}

.drawer {
  color: var(--top-bar-icon-color);
  background-color: var(--top-bar-color);
}

.drawer:focus-within {
  background-color: var(--ui-color-main);
}

.drawer-content:not(#left-nav-panel):not(#right-nav-panel) {
  border-radius: 0 0 var(--border-radius-small) var(--border-radius-small);
}

/* IOS 适配 */
@supports (-webkit-touch-callout: none) {
  .drawer-content:not(#left-nav-panel):not(#right-nav-panel) {
    max-width: 100dvw;
    top: var(--topBarBlockSize);
  }
}
/* IPAD 适配 */
@supports (-webkit-touch-callout: none) {
  @media screen and (min-width: 1000px) {
    #character_popup,
    #world_popup,
    .drawer-content {
      margin-top: 0px;
    }
    #top-settings-holder .drawer .drawer-content {
      right: 0;
      left: 0;
      width: var(--sheldWidth);
    }
    #left-nav-panel,
    #right-nav-panel {
      margin: 0 auto;
      top: calc(var(--topBarBlockSize) + var(--top-distance));
      max-height: calc(100dvh - var(--topBarBlockSize) - var(--bottomFormBlockSize));
      border-radius: 0 0 var(--border-radius-small) var(--border-radius-small);
      border-bottom: 1px solid var(--top-bar-underline-color);
      box-shadow: var(--panel-shadow); /* 确保在iPad上也有阴影 */
    }
  }
}

.drawer-icon {
  opacity: 0.3;
  font-size: calc(var(--icon-size) * 1.1);
